webpackJsonp([0xef49f4fd79c3],{373:function(t,n){t.exports={data:{markdownRemark:{html:'<h4>Schedule</h4>\n<h5>Day 1</h5>\n<table>\n<thead>\n<tr>\n<th>Time</th>\n<th align="center">Description</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>10:00 - 10:45</td>\n<td align="center">Introductions</td>\n</tr>\n<tr>\n<td>10:45 - 11:30</td>\n<td align="center">General Overview of AI</td>\n</tr>\n<tr>\n<td>11:30 - 12:45</td>\n<td align="center">Introduction to ML/DL</td>\n</tr>\n<tr>\n<td>12:45 - 13:45</td>\n<td align="center">Lunch Break</td>\n</tr>\n<tr>\n<td>13:45 - 15:00</td>\n<td align="center">Tools and Setting Up</td>\n</tr>\n<tr>\n<td>15:00 - 16:00</td>\n<td align="center">Exercise: Interactive ML with Runway</td>\n</tr>\n<tr>\n<td>16:00 - 17:00</td>\n<td align="center">Exercise: Creating a custom model</td>\n</tr>\n<tr>\n<td>17:00 - 17:30</td>\n<td align="center">Exercise: ML in the browser</td>\n</tr>\n<tr>\n<td>17:30 - 18:00</td>\n<td align="center">Group Excercise and Project Description</td>\n</tr>\n</tbody>\n</table>\n<h5>Day 2</h5>\n<table>\n<thead>\n<tr>\n<th>Time</th>\n<th align="center">Description</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>10:00 - 10:45</td>\n<td align="center">ML Recap/Questions</td>\n</tr>\n<tr>\n<td>10:45 - 11:30</td>\n<td align="center">Data Collection and Models</td>\n</tr>\n<tr>\n<td>11:30 - 12:45</td>\n<td align="center">Style Transfer Training</td>\n</tr>\n<tr>\n<td>12:45 - 13:45</td>\n<td align="center">Lunch Break</td>\n</tr>\n<tr>\n<td>13:45 - 15:00</td>\n<td align="center">Training an LSTM Network</td>\n</tr>\n<tr>\n<td>15:00 - 16:00</td>\n<td align="center">Group Work</td>\n</tr>\n<tr>\n<td>16:00 - 17:00</td>\n<td align="center">Group Work</td>\n</tr>\n<tr>\n<td>17:00 - 17:30</td>\n<td align="center">Group Work</td>\n</tr>\n<tr>\n<td>17:30 - 18:00</td>\n<td align="center">Project Presentation</td>\n</tr>\n</tbody>\n</table>\n<h4>Materials</h4>\n<ul>\n<li>Workshop code and examples: <a href="https://github.com/cvalenzuela/AA_Autodesk">github.com/cvalenzuela/AA_Autodesk</a></li>\n<li>Runway Download Address: <code>aaschool@runwayml.com</code></li>\n<li>Paperspace $15 Code: <code>AASCHOOL15</code></li>\n</ul>\n<h5>Requirements</h5>\n<ol>\n<li>Please install and download\n<a href="">VSCode</a>, <a href="http://brackets.io/">Brackets</a>, <a href="https://atom.io/">Atom</a> or any code editor</li>\n<li>Download <a href="https://www.docker.com/community-edition">Docker</a>. (You will need to sign in)</li>\n<li>Download <a href="https://runwayml.com/beta/download/">RunwayML</a>. Use the download email address provided.</li>\n</ol>\n<h4>Tools and Frameworks</h4>\n<h5>ML Libraries and Tools</h5>\n<ul>\n<li><a href="http://tensorflow.org/">Tensorflow</a></li>\n<li><a href="https://pytorch.org/">PyTorch</a></li>\n<li><a href="https://ml5js.org/">ml5.js</a></li>\n<li><a href="https://js.tensorflow.org/">tensorflow.js</a></li>\n<li><a href="https://colab.research.google.com/notebooks/welcome.ipynb#recent=true">Google Colab</a></li>\n<li><a href="https://github.com/jupyterlab/jupyterlab">Jupyter Lab/Notebooks</a></li>\n</ul>\n<h5>Graphical Interfaces</h5>\n<ul>\n<li><a href="https://runwayml.com/">RunwayML</a></li>\n<li><a href="http://www.wekinator.org/">Wekinator</a></li>\n</ul>\n<h5>Other</h5>\n<ul>\n<li><a href="http://cmder.net/">cmder</a>: console emulators on Windows. </li>\n</ul>\n<h5>Cloud Computing</h5>\n<ul>\n<li><a href="https://www.paperspace.com/">Paperspace</a>:  </li>\n</ul>\n<h5>Visual</h5>\n<ul>\n<li><a href="https://processing.org/">Processing</a></li>\n<li><a href="https://p5js.org/">p5.js</a></li>\n<li><a href="https://openframeworks.cc/">openFrameworks</a></li>\n</ul>\n<h4>Additional Learning Resources</h4>\n<ul>\n<li><a href="https://ml4a.github.io/">ml4a</a></li>\n<li><a href="https://runwayml.com/tutorials/">Runwayml Tutorials</a></li>\n<li><a href="">Runwayml Slack Channel</a></li>\n<li><a href="https://codelabs.developers.google.com/codelabs/tensorflow-for-poets/">Tensorflow for poets</a></li>\n<li><a href="https://github.com/tensorflow/hub">Tensorflow Hub</a></li>\n<li><a href="https://www.tensorflow.org/tutorials/">Tensorflow Tutorials</a></li>\n<li><a href="https://storage.googleapis.com/openimages/web/index.html">Open Images</a></li>\n<li><a href="https://tools.google.com/seedbank/">Seedbank</a></li>\n</ul>\n<h4>About Cristobal Valenzuela</h4>\n<p>Cristóbal Valenzuela is a technologist, artist and software developer interested in the intersection between machine learning and creative tools. He is a researcher at <a href="https://tisch.nyu.edu/itp">New York University ITP</a> author of <a href="https://runwayml.com/">RunwayML</a>, Creative Resident at <a href="https://www.paperspace.com/">Paperspace</a> and co-founder of <a href="https://latentstudio.com/">Latent Studio</a>, a creative studio specializing in machine learning and artificial intelligence. He also contributes to OSS and helps maintain <a href="https://ml5js.org/"> ml5.js </a>. His work has been sponsored by Google\nand the Processing Foundation and his projects has been exhibited in Latin America and the US, including the Santiago Museum of Contemporary Art, GAM, Fundación Telefonica, Lollapalooza, NYC Media Lab, New Latin Wave, Inter-American Development Bank, Stanford University and New York University.</p>\n<p>cris [at] runwayml.com</p>\n<p><a href="https://twitter.com/c_valenzuelab">@c_valenzuelab</a></p>\n<p>github: <a href="https://github.com/cvalenzuela">cvalenzuela</a></p>',frontmatter:{path:"/workshops/aa",title:"Machine Learning Workshop",subtitle:"Architectural Association & Autodesk",location:"21.07.18 - 22.07.18 | Boston, MA"}}},pathContext:{}}}});
